// Pega a data da última mensagem
const lastMsgDate = new Date($json.last_msg);

// Hora atual
const now = new Date();

// Diferença em minutos
const diffMinutes = (now - lastMsgDate) / (1000 * 60);

// Calcula a rota pelo tempo da última mensagem
let route;
if (diffMinutes > 10) {
  route = '1'; // mais de 10 min
} else if (diffMinutes > 5) {
  route = '2'; // entre 5 e 10 min
} else {
  route = '3'; // menos de 5 min
}

// Calcula código de horário (1 se entre 6h e 22h, senão 0)
const hour = now.getHours();
const horarioCode = (hour >= 6 && hour <= 21) ? 1 : 0;

return [
  {
    json: {
      route,        // rota baseada no tempo
      horarioCode   // código baseado no horário do dia
    }
  }
];

// Este código gera um número inteiro aleatório entre 120 e 300
return [
  {
    json: {
      randomNumber: Math.floor(Math.random() * (60 - 40 + 1)) + 30
    }
  }
];

