// Configuração: tempo médio por caractere (ajustável)
const msPerChar = 30;

// Divide o texto em partes (usando quebra dupla de linha)
const partes = $json.output
  .split(/\r?\n\r?\n/)
  .map(p => p.trim())
  .filter(p => p !== "");

// Mapeia cada parte para um objeto com mensagem e delay
const resultado = partes.map((mensagem, index) => {
  return {
    mensagem: mensagem,
    delay: mensagem.length * msPerChar,
  };
});

// Retorna como output do nó Code
